  }
  getBPStatus(s, d) {
    if (s >= 180 || d > 120) {
      return "Hypertensive Crisis";
    }
    if (s >= 140 || d >= 90) {
      return "Stage 2 Hypertension";
    }
    if (s >= 130 || d >= 80) {
      return "Stage 1 Hypertension";
    }
    if (s >= 120 && d < 80) {
      return "Elevated";
    }
    return "Normal";
  }
  getBPClass(s, d) {
    if (s >= 180 || d >= 120) {
      return "crisis";
    }
    if (s >= 140 || d >= 90) {
      return "stage2";
    }
    if (s >= 130 || d >= 80) {
      return "stage1";
    }
    if (s >= 120 && d < 80) {
      return "elevated";
    }
    return "normal";
  }
